import {useEffect} from "react";

const Alert = ({message, type, duration, onClose}) => {
    useEffect(() => {
        // Tự động ẩn thông báo sau thời gian `duration` (mặc định là 3 giây)
        const timer = setTimeout(() => {
            if (onClose) onClose();// Gọi hàm onClose để ẩn thông báo
        }, duration)
        return () => clearTimeout(timer) // Xóa timer khi component unmount
    }, [message, duration, onClose]);

    if (!message) return null;

    return (
        <div className={`alert alert-${type} alert-dismissible fade show`} role="alert">
            {message}
            <button type="button" className="btn-close" onClick={onClose} aria-label="close"></button>
        </div>
    )
}
export default Alert;
